package com.bandage.musicmetadataservice.application.port.outbound

import com.bandage.musicmetadataservice.domain.model.Artist
import com.bandage.musicmetadataservice.domain.model.Recording

/**
 * 외부 음악 메타데이터 API 호출 포트.
 * 구현체: MusicBrainzApiClient (기본), SpotifyApiClient (비활성)
 */
interface MusicInfoApiClient {
    // ===== 레거시 (Spotify 호환용, deprecated) =====
    @Deprecated("Use searchRecording/searchArtist instead")
    fun getToken(): String = throw UnsupportedOperationException("Not supported")

    @Deprecated("Use searchRecording/searchArtist instead")
    fun getMusicInfo(): String = throw UnsupportedOperationException("Not supported")

    // ===== Recording =====
    fun searchRecording(query: String, limit: Int = 25, offset: Int = 0): List<Recording>
    fun lookupRecording(id: String): Recording?

    // ===== Artist =====
    fun searchArtist(query: String, limit: Int = 25, offset: Int = 0): List<Artist>
    fun lookupArtist(id: String): Artist?
}
```

기존 getToken/getMusicInfo는 default 구현으로 UnsupportedOperationException throw — Spotify 어댑터 하위 호환 유지

`adapter/outbound/external/musicbrainz/MusicBrainzApiClient.kt`:
```kotlin
@Component
@Primary
class MusicBrainzApiClient(
    private val musicBrainzHttpClient: HttpClient,
    private val properties: MusicBrainzApiProperties,
) : MusicInfoApiClient {

    private val mutex = Mutex()
    private var lastCallTime: Instant = Instant.EPOCH

    override fun searchRecording(query: String, limit: Int, offset: Int): List<Recording> =
        runBlocking {
            throttle()
            val response = musicBrainzHttpClient.get("${properties.baseUrl}/ws/2/recording/") {
                parameter("query", query)
                parameter("limit", limit)
                parameter("offset", offset)
                parameter("fmt", "json")
            }
            ensureSuccess(response)
            val dto: MusicBrainzRecordingSearchResponse = response.body()
            dto.recordings.map { it.toDomain() }
        }

    override fun lookupRecording(id: String): Recording? =
        runBlocking {
            throttle()
            val response = musicBrainzHttpClient.get("${properties.baseUrl}/ws/2/recording/$id") {
                parameter("inc", "artists+isrcs+releases")
                parameter("fmt", "json")
            }
            if (response.status.value == 404) return@runBlocking null
            ensureSuccess(response)
            val dto: MusicBrainzRecordingDto = response.body()
            dto.toDomain()
        }

    // searchArtist, lookupArtist 동일 패턴

    private suspend fun throttle() {
        mutex.withLock {
            val elapsed = Duration.between(lastCallTime, Instant.now())
            if (elapsed < Duration.ofSeconds(1)) {
                delay(Duration.ofSeconds(1).minus(elapsed).toMillis())
            }
            lastCallTime = Instant.now()
        }
    }

    private suspend fun ensureSuccess(response: HttpResponse) {
        if (response.status.isSuccess()) return
        val retryAfter = response.headers[HttpHeaders.RetryAfter]?.toLongOrNull()
        throw MusicBrainzApiException(
            statusCode = response.status.value,
            rawBody = response.bodyAsText(),
            retryAfterSeconds = retryAfter,
        )
    }
}
```

